// api.js — central fetch wrapper with consistent error handling.

async function _request(method, path, body) {
  const opts = { method, headers: {} };
  if (body !== undefined) {
    opts.headers['Content-Type'] = 'application/json';
    opts.body = JSON.stringify(body);
  }
  const resp = await fetch(path, opts);
  let payload = null;
  try {
    payload = await resp.json();
  } catch (_) {
    payload = null;
  }
  if (!resp.ok) {
    const detail = payload && (payload.detail || payload.message || JSON.stringify(payload));
    const err = new Error(`${resp.status} ${resp.statusText}${detail ? ': ' + detail : ''}`);
    err.status = resp.status;
    err.payload = payload;
    throw err;
  }
  return payload;
}

export const api = {
  get:   (path)        => _request('GET',    path),
  post:  (path, body)  => _request('POST',   path, body || {}),
  put:   (path, body)  => _request('PUT',    path, body || {}),
  del:   (path)        => _request('DELETE', path),

  // ── Ideas ──
  ideas:    () => _request('GET', '/api/ideas'),

  // ── Drafts ──
  drafts:        () => _request('GET',    '/api/drafts'),
  draft:    (id) => _request('GET',    `/api/drafts/${encodeURIComponent(id)}`),
  draftCreate:   (body) => _request('POST',   '/api/drafts', body),
  draftUpdate:   (id, body) => _request('PUT',    `/api/drafts/${encodeURIComponent(id)}`, body),
  draftDelete:   (id) => _request('DELETE', `/api/drafts/${encodeURIComponent(id)}`),

  // ── Writings ──
  writings:           () => _request('GET',    '/api/writings'),
  writing:       (slug) => _request('GET',    `/api/writings/${encodeURIComponent(slug)}`),
  writingCreate: (body) => _request('POST',   '/api/writings', body),
  writingDelete: (slug) => _request('DELETE', `/api/writings/${encodeURIComponent(slug)}`),
  writingStageWrite: (slug, name, content) =>
    _request('PUT', `/api/writings/${encodeURIComponent(slug)}/stage/${encodeURIComponent(name)}`, { content }),
  writingFeedback: (slug, text, stage) =>
    _request('POST', `/api/writings/${encodeURIComponent(slug)}/feedback`, { text, stage: stage || null }),
  writingApprove: (slug, stage) =>
    _request('POST', `/api/writings/${encodeURIComponent(slug)}/approve`, { stage }),
  writingPublish: (slug, target_dir) =>
    _request('POST', `/api/writings/${encodeURIComponent(slug)}/publish`, { target_dir: target_dir || null }),
  writingMarkRead: (slug) =>
    _request('POST', `/api/writings/${encodeURIComponent(slug)}/feedback-cursor`, {}),
};

// ui.js — small shared UI helpers (date formatting, toast, html escape, css loading).

export function escapeHtml(s) {
  if (s === null || s === undefined) return '';
  return String(s)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

export function fmtTime(iso) {
  if (!iso) return '—';
  const d = new Date(iso);
  if (isNaN(d.getTime())) return iso;
  return d.toLocaleString('zh-CN', {
    month: '2-digit', day: '2-digit',
    hour: '2-digit', minute: '2-digit',
  });
}

export function fmtDate(iso) {
  if (!iso) return '';
  const d = new Date(iso);
  if (isNaN(d.getTime())) return iso;
  return d.toLocaleDateString('zh-CN');
}

const _loadedCss = new Set();
export function ensureCss(href) {
  if (_loadedCss.has(href)) return;
  _loadedCss.add(href);
  const link = document.createElement('link');
  link.rel = 'stylesheet';
  link.href = href;
  document.head.appendChild(link);
}

let _toastEl = null;
let _toastTimer = null;
export function toast(msg, ms) {
  if (!_toastEl) {
    _toastEl = document.createElement('div');
    _toastEl.className = 'toast';
    document.body.appendChild(_toastEl);
  }
  _toastEl.textContent = msg;
  _toastEl.classList.add('show');
  if (_toastTimer) clearTimeout(_toastTimer);
  _toastTimer = setTimeout(() => _toastEl.classList.remove('show'), ms || 1800);
}

export async function loadHtmlFragment(url) {
  const resp = await fetch(url);
  if (!resp.ok) throw new Error('failed to load fragment: ' + url);
  return resp.text();
}

// tabs/ideas.js — Ideas tab module.

import { api } from '../api.js';
import { ensureCss, escapeHtml, loadHtmlFragment } from '../ui.js';

const DIM_LABELS = {
  audience_reach: '受众覆盖',
  distribution_potential: '传播潜力',
  author_differentiation: '作者独特性',
  timeliness: '时效性',
  series_potential: '系列化',
};
const REC_LABELS = { strong: '强烈推荐', moderate: '值得考虑', weak: '优先级低' };

let state = { allData: null, activeDate: 'all' };
let rootEl = null;

function renderIdea(idea) {
  const s = idea.scores || {};
  const dims = Object.entries(DIM_LABELS).map(([k, label]) => {
    const val = s[k] || 0;
    const color = val >= 4 ? '#186246' : val >= 3 ? '#856404' : '#6c757d';
    return `<div class="dim"><div class="dim-label">${label}</div><div class="dim-val" style="color:${color}">${val}</div></div>`;
  }).join('');
  const total = s.total || 0;
  return `
    <div class="card idea-card">
      <div class="idea-header">
        <div class="idea-title"><a href="${escapeHtml(idea.url)}" target="_blank" rel="noopener">${escapeHtml(idea.title)}</a></div>
        <span class="badge ${idea.recommendation}">${REC_LABELS[idea.recommendation] || idea.recommendation || ''}</span>
      </div>
      <div style="display:flex;align-items:baseline;gap:8px">
        <span class="score-total">${total}</span><span class="score-max">/ 25</span>
        <span style="font-size:12px;color:var(--muted)">${escapeHtml(idea.date || '')}</span>
      </div>
      <div class="score-bar">${dims}</div>
      <div class="angle">${escapeHtml(idea.suggested_angle || '')}</div>
      <div class="idea-meta">
        <span class="tag">${escapeHtml(idea.content_line || '')}</span>
        <span>来源: ${escapeHtml(idea.source || '')}</span>
      </div>
    </div>`;
}

function renderDateFilter(dates) {
  const f = rootEl.querySelector('#dateFilter');
  let h = `<button class="date-btn ${state.activeDate === 'all' ? 'active' : ''}" data-date="all">全部</button>`;
  for (const d of dates) {
    h += `<button class="date-btn ${state.activeDate === d ? 'active' : ''}" data-date="${escapeHtml(d)}">${escapeHtml(d)}</button>`;
  }
  f.innerHTML = h;
  f.querySelectorAll('.date-btn').forEach((b) => {
    b.addEventListener('click', () => setDate(b.getAttribute('data-date')));
  });
}

function renderIdeas(ideas) {
  const list = rootEl.querySelector('#ideasList');
  if (!ideas || !ideas.length) {
    list.innerHTML = '<div class="empty">该日期暂无选题推荐</div>';
    return;
  }
  const groups = { strong: [], moderate: [], weak: [] };
  ideas.forEach((i) => (groups[i.recommendation] || groups.weak).push(i));
  let h = '';
  if (groups.strong.length)   h += '<div class="section-label">强烈推荐</div>' + groups.strong.map(renderIdea).join('');
  if (groups.moderate.length) h += '<div class="section-label">值得考虑</div>' + groups.moderate.map(renderIdea).join('');
  if (groups.weak.length)     h += '<div class="section-label">优先级低</div>' + groups.weak.map(renderIdea).join('');
  list.innerHTML = h;
}

function setDate(d) {
  state.activeDate = d;
  if (!state.allData) return;
  renderDateFilter(state.allData.dates || []);
  const filtered = state.activeDate === 'all'
    ? state.allData.ideas
    : (state.allData.ideas || []).filter((i) => i.date === state.activeDate);
  renderIdeas(filtered);
}

async function refresh() {
  try {
    state.allData = await api.ideas();
    renderDateFilter(state.allData.dates || []);
    renderIdeas(state.allData.ideas || []);
    rootEl.querySelector('#genMeta').textContent =
      `更新时间: ${state.allData.generated_at || '未知'} | 保留最近7天`;
  } catch (e) {
    rootEl.querySelector('#ideasList').innerHTML = '<div class="empty">加载失败</div>';
  }
}

export async function mount(root) {
  ensureCss('/static/css/ideas.css');
  rootEl = root;
  rootEl.innerHTML = await loadHtmlFragment('/static/html/ideas.html');
  state = { allData: null, activeDate: 'all' };
  await refresh();
}

export function unmount() {
  rootEl = null;
  state = { allData: null, activeDate: 'all' };
}

// tabs/drafts.js — Drafts tab module (in-line editor + list).

import { api } from '../api.js';
import { ensureCss, escapeHtml, fmtTime, loadHtmlFragment, toast } from '../ui.js';

const STATUS_LABELS = { draft: '草稿中', review: '待审阅', approved: '已通过', published: '已发布' };

let rootEl = null;
let easyMDE = null;
let currentId = null;

function showList() {
  rootEl.querySelector('#draftsListView').style.display = 'block';
  rootEl.querySelector('#draftsEditorView').style.display = 'none';
  if (easyMDE) { easyMDE.toTextArea(); easyMDE = null; }
  currentId = null;
}

function showEditor() {
  rootEl.querySelector('#draftsListView').style.display = 'none';
  rootEl.querySelector('#draftsEditorView').style.display = 'block';
}

async function loadList() {
  try {
    const data = await api.drafts();
    const drafts = data.drafts || [];
    rootEl.querySelector('#draftCount').textContent = `共 ${drafts.length} 篇草稿`;
    if (!drafts.length) {
      rootEl.querySelector('#draftsList').innerHTML =
        '<div class="empty">暂无草稿<br/><span style="font-size:13px;color:var(--muted)">Tom-Blogs-Manager 写完文章后会出现在这里</span></div>';
      return;
    }
    rootEl.querySelector('#draftsList').innerHTML = drafts.map((d) => `
      <div class="card draft-card" data-id="${escapeHtml(d.id)}">
        <div class="draft-header">
          <div class="draft-title">${escapeHtml(d.title)}</div>
          <span class="status-badge ${escapeHtml(d.status)}">${STATUS_LABELS[d.status] || d.status}</span>
        </div>
        <div class="draft-time">创建: ${fmtTime(d.created_at)} &nbsp;|&nbsp; 更新: ${fmtTime(d.updated_at)}</div>
      </div>
    `).join('');
    rootEl.querySelectorAll('.draft-card').forEach((c) => {
      c.addEventListener('click', () => openDraft(c.getAttribute('data-id')));
    });
  } catch (e) {
    rootEl.querySelector('#draftsList').innerHTML = '<div class="empty">加载失败</div>';
  }
}

async function openDraft(id) {
  try {
    const draft = await api.draft(id);
    currentId = id;
    rootEl.querySelector('#draftTitle').value = draft.title;
    rootEl.querySelector('#statusSelect').value = draft.status;
    rootEl.querySelector('#draftMeta').textContent = `创建: ${fmtTime(draft.created_at)} | 更新: ${fmtTime(draft.updated_at)}`;
    rootEl.querySelector('#saveStatus').textContent = '';
    showEditor();
    if (easyMDE) { easyMDE.toTextArea(); easyMDE = null; }
    easyMDE = new EasyMDE({
      element: rootEl.querySelector('#draftEditor'),
      initialValue: draft.content || '',
      spellChecker: false,
      autofocus: true,
      minHeight: '400px',
      placeholder: '在此编辑文章内容 (Markdown)...',
      status: ['lines', 'words'],
      toolbar: [
        'bold', 'italic', 'heading', '|',
        'quote', 'unordered-list', 'ordered-list', '|',
        'link', 'image', 'code', '|',
        'preview', 'side-by-side', 'fullscreen', '|',
        'guide',
      ],
      renderingConfig: { markedOptions: { breaks: true } },
    });
  } catch (e) {
    toast('打开草稿失败');
