input.new_string:
function tabFromHash() {
  // The hash may carry a sub-route like "#writings/draft" — only the segment
  // before the first "/" identifies the active tab.
  const h = (location.hash || '').replace(/^#/, '').split('/')[0];
  return TABS[h] ? h : DEFAULT_TAB;
}

